from machine import Pin, ADC
from time import sleep
from umqtt.simple import MQTTClient

# MQTT Configuration
broker_ip = '192.168.1.100'  # Replace with your broker IP
client_id = 'esp32_sensor'
topic = 'sensors/temp'

# Set up the temperature sensor (for example, using an analog sensor)
analog_pin = 34
adc = ADC(Pin(analog_pin))
adc.atten(ADC.ATTN_11DB)  # Set the attenuation for full range

# Connect to MQTT Broker
client = MQTTClient(client_id, broker_ip)
client.connect()

def read_temperature():
    raw_value = adc.read()
    # Convert raw ADC value to temperature (Assuming a range e.g., 0-100 degrees)
    temperature = (raw_value / 4095.0) * 100
    return temperature

try:
    while True:
        temp = read_temperature()
        temp_str = '{:.2f}'.format(temp)
        client.publish(topic, temp_str)
        print("Published temperature: ", temp_str)
        sleep(10)  # Delay between readings
finally:
    client.disconnect()